export function getMediaPostById(id: string): MediaPost | undefined {
  return mediaPosts.find((post) => post.id === id);
}

function sortByDateDesc(posts: MediaPost[]): MediaPost[] {
  return [...posts].sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());
}

export function getAllMediaPosts(): MediaPost[] {
  return sortByDateDesc(mediaPosts);
}

// microCMS fetch
async function fetchFromMicroCMS<T>(endpoint: string, fallback: T): Promise<T> {
  if (!API_KEY || !SERVICE_ID) return fallback;
  try {
    const res = await fetch(
      `https://${SERVICE_ID}.microcms.io/api/v1/${endpoint}?limit=100`,
      {
        headers: { "X-MICROCMS-API-KEY": API_KEY },
        next: { revalidate: 60 },
      }
    );
    if (!res.ok) return fallback;
    return (await res.json()) as T;
  } catch {
    return fallback;
  }
}

export async function getAllMediaFromCMS(): Promise<MediaPost[]> {
  const data = await fetchFromMicroCMS<MicroCMSListResponse>("media", { contents: [] });
  if (!data.contents || data.contents.length === 0) return sortByDateDesc(mediaPosts);

  const cmsIds = new Set(data.contents.map((item) => item.id));
  const posts = data.contents.map((item) => {
    const cat = Array.isArray(item.category)
      ? item.category[0] || "appear"
      : "appear";
    const staticPost = mediaPosts.find((p) => p.id === item.id);
    return {
      id: item.id,
      category: cat as "radio" | "guest" | "appear" | "note",
      categoryLabel: categoryLabelMap[cat] || "雑記",
      date: item.date ? formatDate(item.date) : staticPost?.date || "",
      title: item.title || staticPost?.title || "",
      excerpt: item.excerpt || staticPost?.excerpt || "",
      youtubeUrl: item.youtubeUrl || staticPost?.youtubeUrl || null,
      thumbnail: staticPost?.thumbnail || "",
      theme: staticPost?.theme || "",
      summary: staticPost?.summary || [],
      quotes: staticPost?.quotes || [],
      transcript: item.transcript || staticPost?.transcript || "",
      tags: staticPost?.tags || [],
      guests: staticPost?.guests,
      hostIds: staticPost?.hostIds,
    };
  });
  // Also include static entries not present in CMS
  const staticOnly = mediaPosts.filter((p) => !cmsIds.has(p.id));
  return sortByDateDesc([...posts, ...staticOnly]);
}

export async function getMediaByIdFromCMS(id: string): Promise<MediaPost | undefined> {
  try {
    const res = await fetch(
      `https://${SERVICE_ID}.microcms.io/api/v1/media/${id}`,
      {
        headers: { "X-MICROCMS-API-KEY": API_KEY },
        next: { revalidate: 60 },
      }
    );
    if (!res.ok) return mediaPosts.find((p) => p.id === id);
    const item = (await res.json()) as MicroCMSMediaItem;
    const cat = Array.isArray(item.category)
      ? item.category[0] || "appear"
      : "appear";
    const staticPost = mediaPosts.find((p) => p.id === item.id);

    return {
      id: item.id,
      category: cat as "radio" | "guest" | "appear" | "note",
      categoryLabel: categoryLabelMap[cat] || "雑記",
      date: item.date ? formatDate(item.date) : staticPost?.date || "",
      title: item.title || staticPost?.title || "",
      excerpt: item.excerpt || staticPost?.excerpt || "",
      youtubeUrl: item.youtubeUrl || staticPost?.youtubeUrl || null,
      thumbnail: staticPost?.thumbnail || "",
      theme: staticPost?.theme || "",
      summary: staticPost?.summary || [],
      quotes: staticPost?.quotes || [],
      transcript: item.transcript || staticPost?.transcript || "",
      tags: staticPost?.tags || [],
      guests: staticPost?.guests,
      hostIds: staticPost?.hostIds,
    };
  } catch {
    return mediaPosts.find((p) => p.id === id);
  }
}
